/*
 * NETCONF Message Builder and Parser for IoT Device Management
 * Demonstrates XML message construction and basic parsing for NETCONF protocol
 * Compile: gcc -o netconf_client netconf_client.c -lxml2 -lcurl
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libxml/parser.h>
#include <libxml/tree.h>
#include <libxml/xpath.h>

/* NETCONF namespaces and constants */
#define NETCONF_NS "urn:ietf:params:xml:ns:netconf:base:1.0"
#define IOT_NS "http://example.com/ns/iot-sensor"
#define MAX_BUFFER 4096

/* NETCONF operation types */
typedef enum {
 NETCONF_GET_CONFIG,
 NETCONF_EDIT_CONFIG,
 NETCONF_GET,
 NETCONF_LOCK,
 NETCONF_UNLOCK,
 NETCONF_COMMIT,
 NETCONF_DISCARD,
 NETCONF_CLOSE_SESSION
} NetconfOperation;

/* Structure to hold NETCONF response */
typedef struct {
 int message_id;
 char *raw_xml;
 int ok_status; /* 1 if <ok/>, 0 if error */
 char *error_type;
 char *error_tag;
 char *error_message;
} NetconfResponse;

/* Global message ID counter */
static int g_message_id = 100;

/*
 * Generate next message ID
 */
int get_next_message_id(void) {
 return g_message_id++;
}

/*
 * Create XML document with NETCONF RPC envelope
 */
xmlDocPtr create_netconf_rpc(const char *operation, int msg_id) {
 xmlDocPtr doc = xmlNewDoc(BAD_CAST "1.0");
 xmlNodePtr root = xmlNewNode(NULL, BAD_CAST "rpc");

 /* Set namespace */
 xmlNsPtr ns = xmlNewNs(root, BAD_CAST NETCONF_NS, NULL);
 (void)ns; /* Suppress unused warning */

 xmlDocSetRootElement(doc, root);

 /* Add message-id attribute */
 char msg_id_str[16];
 sprintf(msg_id_str, "%d", msg_id);
 xmlNewProp(root, BAD_CAST "message-id", BAD_CAST msg_id_str);

 return doc;
}

/*
 * Build <get-config> RPC message
 */
char* build_get_config_rpc(const char *source) {
 int msg_id = get_next_message_id();
 xmlDocPtr doc = create_netconf_rpc("get-config", msg_id);
 xmlNodePtr root = xmlDocGetRootElement(doc);

 /* Create get-config element */
 xmlNodePtr get_config = xmlNewChild(root, NULL, 
 BAD_CAST "get-config", NULL);

 /* Target element */
 xmlNodePtr target = xmlNewChild(get_config, NULL, 
 BAD_CAST "target", NULL);
 xmlNewChild(target, NULL, BAD_CAST source, NULL);

 /* Output to string */
 xmlChar *xml_buf;
 int xml_buf_size;
 xmlDocDumpFormatMemory(doc, &xml_buf, &xml_buf_size, 1);

 char *result = strdup((char*)xml_buf);
 xmlFree(xml_buf);
 xmlFreeDoc(doc);

 return result;
}

/*
 * Build <edit-config> RPC for IoT device configuration
 */
char* build_edit_config_rpc(const char *device_id, 
 int sampling_interval,
 float reporting_threshold,
 int enabled) {
 int msg_id = get_next_message_id();
 xmlDocPtr doc = create_netconf_rpc("edit-config", msg_id);
 xmlNodePtr root = xmlDocGetRootElement(doc);

 /* Create edit-config element */
 xmlNodePtr edit_config = xmlNewChild(root, NULL, 
 BAD_CAST "edit-config", NULL);

 /* Target element */
 xmlNodePtr target = xmlNewChild(edit_config, NULL, 
 BAD_CAST "target", NULL);
 xmlNewChild(target, NULL, BAD_CAST "candidate", NULL);

 /* Default operation */
 xmlNewProp(edit_config, BAD_CAST "default-operation", 
 BAD_CAST "merge");

 /* Config element */
 xmlNodePtr config = xmlNewChild(edit_config, NULL, 
 BAD_CAST "config", NULL);

 /* IoT device container with namespace */
 xmlNsPtr iot_ns = xmlNewNs(config, BAD_CAST IOT_NS, 
 BAD_CAST "iot");
 (void)iot_ns;

 xmlNodePtr iot_device = xmlNewChild(config, NULL, 
 BAD_CAST "iot-device", NULL);
 xmlNewProp(iot_device, BAD_CAST "xmlns", BAD_CAST IOT_NS);

 /* Device ID leaf */
 xmlNewChild(iot_device, NULL, BAD_CAST "device-id", 
 BAD_CAST device_id);

 /* Sampling interval leaf */
 char samp_int_str[16];
 sprintf(samp_int_str, "%d", sampling_interval);
 xmlNewChild(iot_device, NULL, BAD_CAST "sampling-interval", 
 BAD_CAST samp_int_str);

 /* Reporting threshold leaf */
 char thresh_str[16];
 sprintf(thresh_str, "%.2f", reporting_threshold);
 xmlNewChild(iot_device, NULL, BAD_CAST "reporting-threshold", 
 BAD_CAST thresh_str);

 /* Enabled leaf */
 xmlNewChild(iot_device, NULL, BAD_CAST "enabled", 
 BAD_CAST (enabled ? "true" : "false"));

 /* Output to string */
 xmlChar *xml_buf;
 int xml_buf_size;
 xmlDocDumpFormatMemory(doc, &xml_buf, &xml_buf_size, 1);

 char *result = strdup((char*)xml_buf);
 xmlFree(xml_buf);
 xmlFreeDoc(doc);

 return result;
}

/*
 * Build <lock> RPC message
 */
char* build_lock_rpc(const char *target) {
 int msg_id = get_next_message_id();
 xmlDocPtr doc = create_netconf_rpc("lock", msg_id);
 xmlNodePtr root = xmlDocGetRootElement(doc);

 xmlNodePtr lock = xmlNewChild(root, NULL, BAD_CAST "lock", NULL);
 xmlNodePtr lock_target = xmlNewChild(lock, NULL, 
 BAD_CAST "target", NULL);
 xmlNewChild(lock_target, NULL, BAD_CAST target, NULL);

 xmlChar *xml_buf;
 int xml_buf_size;
 xmlDocDumpFormatMemory(doc, &xml_buf, &xml_buf_size, 1);

 char *result = strdup((char*)xml_buf);
 xmlFree(xml_buf);
 xmlFreeDoc(doc);

 return result;
}

/*
 * Build <commit> RPC message
 */
char* build_commit_rpc(void) {
 int msg_id = get_next_message_id();
 xmlDocPtr doc = create_netconf_rpc("commit", msg_id);

 xmlChar *xml_buf;
 int xml_buf_size;
 xmlDocDumpFormatMemory(doc, &xml_buf, &xml_buf_size, 1);

 char *result = strdup((char*)xml_buf);
 xmlFree(xml_buf);
 xmlFreeDoc(doc);

 return result;
}

/*
 * Build <close-session> RPC message
 */
char* build_close_session_rpc(void) {
 int msg_id = get_next_message_id();
 xmlDocPtr doc = create_netconf_rpc("close-session", msg_id);

 xmlChar *xml_buf;
 int xml_buf_size;
 xmlDocDumpFormatMemory(doc, &xml_buf, &xml_buf_size, 1);

 char *result = strdup((char*)xml_buf);
 xmlFree(xml_buf);
 xmlFreeDoc(doc);

 return result;
}

/*
 * Parse NETCONF response
 */
NetconfResponse* parse_rpc_reply(const char *xml_response) {
 NetconfResponse *resp = malloc(sizeof(NetconfResponse));
 memset(resp, 0, sizeof(NetconfResponse));
 resp->raw_xml = strdup(xml_response);
 resp->ok_status = 0;

 xmlDocPtr doc = xmlReadMemory(xml_response, strlen(xml_response), 
 "noname.xml", NULL, 0);
 if (!doc) {
 return resp;
 }

 xmlNodePtr root = xmlDocGetRootElement(doc);
 if (!root) {
 xmlFreeDoc(doc);
 return resp;
 }

 /* Get message-id */
 xmlChar *msg_id = xmlGetProp(root, BAD_CAST "message-id");
 if (msg_id) {
 resp->message_id = atoi((char*)msg_id);
 xmlFree(msg_id);
 }

 /* Check for <ok/> response */
 xmlNodePtr child = root->children;
 while (child) {
 if (!xmlStrcmp(child->name, BAD_CAST "ok")) {
 resp->ok_status = 1;
 break;
 }
 if (!xmlStrcmp(child->name, BAD_CAST "rpc-error")) {
 /* Parse error details */
 xmlNodePtr err_child = child->children;
 while (err_child) {
 if (!xmlStrcmp(err_child->name, BAD_CAST "error-type")) {
 resp->error_type = (char*)xmlNodeGetContent(err_child);
 }
 if (!xmlStrcmp(err_child->name, BAD_CAST "error-tag")) {
 resp->error_tag = (char*)xmlNodeGetContent(err_child);
 }
 if (!xmlStrcmp(err_child->name, BAD_CAST "error-message")) {
 resp->error_message = (char*)xmlNodeGetContent(err_child);
 }
 err_child = err_child->next;
 }
 }
 child = child->next;
 }

 xmlFreeDoc(doc);
 return resp;
}

/*
 * Free NETCONF response structure
 */
void free_response(NetconfResponse *resp) {
 if (resp) {
 if (resp->raw_xml) free(resp->raw_xml);
 if (resp->error_type) xmlFree(resp->error_type);
 if (resp->error_tag) xmlFree(resp->error_tag);
 if (resp->error_message) xmlFree(resp->error_message);
 free(resp);
 }
}

/*
 * Example: Complete NETCONF transaction workflow
 */
void demonstrate_netconf_workflow(void) {
 printf("=== NETCONF Message Building Demo ===\n\n");

 /* Step 1: Build get-config request */
 printf("1. Get Config Request:\n");
 char *get_config = build_get_config_rpc("running");
 printf("%s\n\n", get_config);
 free(get_config);

 /* Step 2: Build lock request */
 printf("2. Lock Request:\n");
 char *lock_req = build_lock_rpc("candidate");
 printf("%s\n\n", lock_req);
 free(lock_req);

 /* Step 3: Build edit-config request */
 printf("3. Edit Config Request (IoT Device):\n");
 char *edit_config = build_edit_config_rpc("sensor-123", 30, 25.5, 1);
 printf("%s\n\n", edit_config);
 free(edit_config);

 /* Step 4: Build commit request */
 printf("4. Commit Request:\n");
 char *commit_req = build_commit_rpc();
 printf("%s\n\n", commit_req);
 free(commit_req);

 /* Step 5: Build close-session request */
 printf("5. Close Session Request:\n");
 char *close_req = build_close_session_rpc();
 printf("%s\n\n", close_req);
 free(close_req);

 /* Demonstrate response parsing */
 printf("6. Parse Response Example:\n");
 const char *sample_response = 
 "<rpc-reply message-id=\"101\" "
 "xmlns=\"urn:ietf:params:xml:ns:netconf:base:1.0\">\n"
 " <ok/>\n"
 "</rpc-reply>";

 NetconfResponse *resp = parse_rpc_reply(sample_response);
 printf("Message ID: %d\n", resp->message_id);
 printf("OK Status: %s\n", resp->ok_status ? "Success" : "Failed");
 free_response(resp);
}

int main(int argc, char **argv) {
 (void)argc; (void)argv;

 /* Initialize XML library */
 xmlInitParser();

 /* Demonstrate NETCONF message building */
 demonstrate_netconf_workflow();

 /* Cleanup XML library */
 xmlCleanupParser();

 return 0;
}
